  const values = [];
  const ops = [];
  const prec = { '+': 1, '-': 1, '*': 2, '/': 2 };
  const applyOp = () => {
    const op = ops.pop();
    const b = values.pop();
    const a = values.pop();
    let res = 0;
    switch (op) {
      case '+': res = a + b; break;
