      case '/': res = Math.trunc(a / b); break;
    }
    values.push(res);
  };
  let i = 0;
  while (i < s.length) {
    const ch = s[i];
    if (ch === '(') {
      ops.push(ch);
      i++;
      continue;
    }
    if (ch === ')') {
      while (ops.length && ops[ops.length - 1] !== '(') applyOp();
      if (ops.length && ops[ops.length - 1] === '(') ops.pop();
      i++;
      continue;
    }
    if (/[0-9]/.test(ch)) {
