    if ('+-*/'.includes(ch)) {
      while (ops.length && ops[ops.length - 1] !== '(' && prec[ops[ops.length - 1]] >= prec[ch]) {
        applyOp();
      }
      ops.push(ch);
      i++;
      continue;
