  while i < len(s):
    ch = s[i]
    if ch.isdigit():
      j = i
      val = 0
      while j < len(s) and s[j].isdigit():
        val = val * 10 + int(s[j])
        j += 1
      values.append(val)
      i = j
      continue
    if ch == '(':
      ops.append(ch)
      i += 1
      continue
    if ch == ')':
      while ops and ops[-1] != '(': apply()
      if ops and ops[-1] == '(': ops.pop()
      i += 1
      continue
    if ch in '+-*/':
      while ops and ops[-1] != '(' and prec[ops[-1]] >= prec[ch]:
